<template>
  <div>
    <van-sticky>
      <van-nav-bar
        title="委托单基本信息"
        left-arrow
        @click-left="onClickLeft"
        @click-right="onClickRight"
      />
    </van-sticky>

    <van-form @submit="onSubmit" style="margin-bottom: 1.52rem">
      <van-field
        readonly
        clickable
        name="entrustType"
        :value="form.entrustType"
        label="委托方式"
        placeholder="委托方式"
        @click="showPicker = true"
        :rules="[{ required: true, message: '请填写委托方式' }]"
      />
      <van-popup v-model="showPicker" position="bottom">
        <van-picker
          show-toolbar
          :columns="entrustTypecolumns"
          @confirm="entrustTypeonConfirm"
          @cancel="showPicker = false"
        />
      </van-popup>

      <van-field
        v-model="form.comName"
        name="comName"
        label="委托单位"
        placeholder="委托单位"
        :rules="[{ required: true, message: '请填写委托单位' }]"
      />
      <van-field
        v-model="form.entrustPeople"
        name="entrustPeople"
        label="委托人"
        placeholder="委托人"
        :rules="[{ required: true, message: '请填写委托人' }]"
      />
      <van-field
        v-model="form.entrustPeoplePhone"
        name="entrustPeoplePhone"
        label="联系电话"
        placeholder="委托人联系电话"
        :rules="[{ required: true, message: '请填写联系电话' }]"
      />
      <van-field
        v-model="form.witnessPeople"
        name="witnessPeople"
        label="见证人"
        placeholder="见证人"
        :rules="[{ required: true, message: '请填写见证人' }]"
      />
      <van-field
        v-model="form.projectId"
        name="projectId"
        label="工程名称"
        placeholder="工程名称"
        :rules="[{ required: true, message: '请填写工程名称' }]"
      />
      <van-field
        v-model="form.projectPart"
        name="projectPart"
        label="工程部位"
        placeholder="工程部位"
        :rules="[{ required: true, message: '请填写工程部位' }]"
      />

      <van-field
        v-model="form.witnessCompanyName"
        name="witnessCompanyName"
        label="见证单位"
        placeholder="见证单位"
        :rules="[{ required: true, message: '请填写见证单位' }]"
      />

      <van-field
        readonly
        clickable
        name="checkPurpose"
        :value="form.checkPurpose"
        label="检验目的"
        placeholder="检验目的"
        @click="checkPurposeshowPicker = true"
        :rules="[{ required: true, message: '请填写检验目的' }]"
      />
      <van-popup v-model="checkPurposeshowPicker" position="bottom">
        <van-picker
          show-toolbar
          :columns="checkPurposecolumns"
          @confirm="checkPurposeonConfirm"
          @cancel="checkPurposeshowPicker = false"
        />
      </van-popup>

      <van-field
        readonly
        clickable
        name="sampleReceiveWay"
        :value="form.sampleReceiveWay"
        label="取样方式"
        placeholder="取样方式"
        @click="sampleReceiveWayshowPicker = true"
        :rules="[{ required: true, message: '请填写取样方式' }]"
      />
      <van-popup v-model="sampleReceiveWayshowPicker" position="bottom">
        <van-picker
          show-toolbar
          :columns="sampleReceiveWaycolumns"
          @confirm="sampleReceiveWayConfirm"
          @cancel="sampleReceiveWayshowPicker = false"
        />
      </van-popup>

      <van-field
        readonly
        clickable
        name="reportGetWay"
        :value="form.reportGetWay"
        label="取报告方式"
        placeholder="取报告方式"
        @click="reportGetWayshowPicker = true"
        :rules="[{ required: true, message: '请填写取报告方式' }]"
      />
      <van-popup v-model="reportGetWayshowPicker" position="bottom">
        <van-picker
          show-toolbar
          :columns="reportGetWaycolumns"
          @confirm="reportGetWayConfirm"
          @cancel="reportGetWayshowPicker = false"
        />
      </van-popup>
      <van-field name="reportNum" label="报告份数">
        <template #input>
          <van-stepper v-model="form.reportNum" />
        </template>
      </van-field>
      <!-- <van-field
        v-model="entrustData"
        name="entrustData"
        label="提供资料"
        placeholder="提供资料"
        :rules="[{ required: true, message: '请填写提供资料' }]"
      /> -->
      <van-field
        v-model="form.entrustNote"
        name="entrustNote"
        label="备注"
        placeholder="备注"
        :rules="[{ required: true, message: '请填写备注' }]"
      />
      <div class="bootom"></div>
      <div class="ista_fix">
        <van-button round block type="info" native-type="submit"
          >下一步</van-button
        >
      </div>
    </van-form>
  </div>
</template>
<script>
import { Toast } from "vant";
import { mapMutations } from "vuex";
import { getselectlist } from "../../utils/http/api";

export default {
  name: "ista",

  data() {
    return {
      form: {
        entrustType: "",
        comName: "",
        entrustPeople: "",
        entrustPeoplePhone: "",
        witnessPeople: "",
        projectId: "",
        projectPart: "",
        checkPurpose: "",
        sampleReceiveWay: "",
        reportGetWay: "",
        reportNum: 1,
        entrustNote: "",
        witnessCompanyName: "",
      },
      // entrustData: "",
      entrustTypecolumns: [],
      checkPurposecolumns: [],
      sampleReceiveWaycolumns: [],
      reportGetWaycolumns: [],
      showPicker: false,
      checkPurposeshowPicker: false,
      sampleReceiveWayshowPicker: false,
      reportGetWayshowPicker: false,
      Way: [],
    };
  },
  created() {
    let obj = this.$store.state.entrustInfo;
    if (
      typeof this.$store.state.entrustInfo === "string" &&
      this.$store.state.entrustInfo !== ""
    ) {
      Object.assign(this.form, JSON.parse(obj));
    } else if (typeof this.$store.state.entrustInfo === "object") {
      Object.assign(this.form, obj);
    } else {
      console.log("No mseeage！！！");
    }
    this.init();
  },

  methods: {
    ...mapMutations(["setentrustInfo", "delentrustInfo"]),
    init() {
      getselectlist().then((res) => {
        let { data } = res.data;
        data.entrustWay.map((item) => {
          this.Way.push(item);
          this.entrustTypecolumns.push(item.label);
        });
        data.checkPurpose.map((item) => {
          this.checkPurposecolumns.push(item.label);
        });
        data.receiveWay.map((item) => {
          this.sampleReceiveWaycolumns.push(item.label);
        });
        data.reportGetWay.map((item) => {
          this.reportGetWaycolumns.push(item.label);
        });
      });
    },

    onSubmit(values) {
      // console.log("submit", values);
      let entrustInfo = {};
      Object.assign(entrustInfo, values);
      // entrustInfo.entrustType = this.Way.filter((item) => {
      //   return item.label === entrustInfo.entrustType;
      // })[0].value;
      this.setentrustInfo(entrustInfo);
      this.$router.push({ name: "istalist" });
    },
    onClickLeft() {
      this.$router.go(-1);
    },
    onClickRight() {},

    entrustTypeonConfirm(value, index) {
      this.form.entrustType = value;
      this.showPicker = false;
    },

    checkPurposeonConfirm(value, index) {
      this.form.checkPurpose = value;
      this.checkPurposeshowPicker = false;
    },

    sampleReceiveWayConfirm(value, index) {
      this.form.sampleReceiveWay = value;
      this.sampleReceiveWayshowPicker = false;
    },
    reportGetWayConfirm(value, index) {
      this.form.reportGetWay = value;
      this.reportGetWayshowPicker = false;
    },
  },
};
</script>

<style lang="less">
.ista_fix {
  position: fixed;
  bottom: 0px;
  background: @gray-2;
  width: 7.5rem;
  padding: 0.32rem;
  box-sizing: border-box;
}
.bootom {
  width: 7.5rem;
  height: 76px;
}
</style>
